package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.ContextKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.AFTROK_EVUD_VWG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.SUPPLEMENT_MET_ENKEL_BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.NIET_BELASTBAAR_APO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_BRUG_PENSIOEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_OVERUREN_GECO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_RSZ_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_TAO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_WINST_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_WVL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_ZIV_GEPENSIONEERD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_GEPENSIONEERD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_LAGE_LONEN_KEY;

@Slf4j
public class BerekenTotaalBelastbaar extends AbstractRekenCommand {

    private static final LocalDate START_REGIME_20_VVAA_GB_AFTROK_SOC_INH = new LocalDate(2024, 1, 1);

    public BerekenTotaalBelastbaar(NlpGlobalService service) {
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        RekenTijd rekenTijd = mainContext.getRekenTijd();
        for (Opdracht opdracht : opdrachten) {
            log.debug(LogTools.toSimpleLog(opdracht));
            vormBelastbaar(rekenTijd, opdracht, manager.getOpdrachtsElementen(opdracht));
        }
        log.trace("persoonsElementen:{}", manager.getPersoonsElementen());
        return CONTINUE_PROCESSING;
    }

    public void vormBelastbaar(RekenTijd rekenTijd, Opdracht opdracht, Collection<LoonElement> loonElementen) {
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        if (hoedanigheid != Hoedanigheid.ONTHAALOUDERS) {
            for (LoonElement element : loonElementen) {
                vormBelastbaar(element, rekenTijd);
            }
        }
    }

    private void vormBelastbaar(LoonElement element, RekenTijd rekenTijd) {
        String logString = "";
        LnedefRegBv regimeBv = element.getRegimeBv();
        log.debug("regimeBv:{};element:{}", regimeBv, element);
        Money belastbaar;
        Money bruto = Money.ZERO;
        AardKodeExtensie loonCode = element.getAardKodeExtensie();
        boolean isAftrokEnkelvoudigVakantiegeld = loonCode.behoortTotGroep(AFTROK_EVUD_VWG_KEY);
        boolean isEnkelBelastbaar = loonCode.behoortTotGroep(SUPPLEMENT_MET_ENKEL_BELASTBAAR_KEY);
        if (isEnkelBelastbaar) {
            bruto = element.getPropertyMoney(BASIS_SOCIALE_INHOUDINGEN_KEY);
        } else if (regimeBv != LnedefRegBv.VD_BV_10_VVAA_GB_AFTROK_SOC_INH && !isAftrokEnkelvoudigVakantiegeld) {
            bruto = element.getPropertyMoney(BRUTO_MAANDLOON_KEY);
            bruto = bruto.subtract(element.getPropertyMoney(NIET_BELASTBAAR_APO_KEY));
        }

        logString = ";bruto:" + bruto;
        if (isRegimeMetVerwerkSocialeBijdragen(regimeBv, rekenTijd)) {
            Money socialeBijdrage = getSocialeBijdrage(element);
            Money werkbonusLageLonen = element.getPropertyMoney(WERKBONUS_LAGE_LONEN_KEY);
            Money werkbonusHeelLageLonen = element.getPropertyMoney(WERKBONUS_HEEL_LAGE_LONEN_KEY);
            Money verminderingHerstructurering = element.getPropertyMoney(VERMINDERING_HERSTRUCTERING_KEY);
            Money werkbonusGepensioneerd = element.getPropertyMoney(WERKBONUS_GEPENSIONEERD_KEY);
            belastbaar =
                    bruto.subtract(socialeBijdrage).add(werkbonusLageLonen).add(werkbonusHeelLageLonen).add(verminderingHerstructurering).add(werkbonusGepensioneerd);
            logString += ";socialeBijdrage:" + socialeBijdrage + ";werkbonusLageLonen:" + werkbonusLageLonen + ";verminderingHerstructurering:"
                    + verminderingHerstructurering;
        } else {
            belastbaar = bruto;
        }

        log.debug("belastbaar:{}{}", belastbaar, logString);
        element.putProperty(BELASTBAAR_KEY, belastbaar);
    }

    private static final ContextKey[] SOCIALE_BIJDRAGEN =
            {BIJDRAGE_RSZ_KEY, BIJDRAGE_TAO_KEY, BIJDRAGE_OVERUREN_GECO_KEY, BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY, BIJDRAGE_ZIV_GEPENSIONEERD_KEY,
                    BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY, BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY, BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY,
                    BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY, BIJDRAGE_PENSIOEN_MANDATARIS_KEY, SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY, BIJDRAGE_WVL_KEY,
                    BIJDRAGE_BRUG_PENSIOEN_KEY, BIJDRAGE_WINST_PREMIE_KEY};

    private Money getSocialeBijdrage(LoonElement element) {
        Money socialeBijdrage = Money.ZERO;
        for (ContextKey socialeBijdrageKey : SOCIALE_BIJDRAGEN) {
            socialeBijdrage = socialeBijdrage.add(element.getPropertyMoney(socialeBijdrageKey));
        }
        return socialeBijdrage;
    }

    private boolean isRegimeMetVerwerkSocialeBijdragen(LnedefRegBv regimeBv, RekenTijd rekenTijd) {
        return regimeBv != LnedefRegBv.VD_BV_10_VVAA_GB_BRUTO &&
                (rekenTijd.eindDatum.isBefore(START_REGIME_20_VVAA_GB_AFTROK_SOC_INH) || regimeBv != LnedefRegBv.VD_BV_10_VVAA_GB_AFTROK_SOC_INH);
    }

}
